const data = $input.first().json;
const body = data.body || data;
const message = body.message || body;

const messageType = message.type || body.type || '';
const isEOCR = messageType === 'end-of-call-report';

if (!isEOCR) {
  return [{ json: { skip: true, reason: 'Not EOCR: ' + messageType } }];
}

const call = message.call || body.call || {};
const artifact = message.artifact || body.artifact || {};
const analysis = message.analysis || body.analysis || {};
const sd = analysis.structuredData || {};

const callId = call.id || '';
const customerNumber = call.customer?.number || '';
const phone9 = customerNumber.replace('+34','').replace('+','').trim().slice(-9);
const phoneE164 = '+34' + phone9;
const assistantId = call.assistantId || '';
const duration = call.costBreakdown?.duration || call.duration || 0;
const cost = call.costBreakdown?.total || call.cost || 0;
const endedReason = call.endedReason || '';
const transcript = artifact.transcript || '';
const recordingUrl = artifact.recordingUrl || '';
const summary = analysis.summary || '';
const successEval = analysis.successEvaluation || '';

// Structured data from VAPI analysisPlan
const resultado = sd.resultado || '';
const citaAgendada = sd.cita_agendada || false;
const nombreContacto = sd.nombre_contacto || '';
const objecion = sd.objecion_principal || '';
const interes = sd.interes_percibido || '';
const callbackDatetime = sd.callback_datetime || '';
const email = sd.email || '';

const fecha = new Date().toISOString();

// Determine assistant type
const isPBOut = assistantId === '03a2bdfd-c35d-4116-ab53-a91eb24774f8';

return [{ json: {
  skip: false,
  callId,
  customerNumber,
  phone: phoneE164,
  phone9,
  assistantId,
  isPBOut,
  duration,
  cost,
  endedReason,
  transcript: transcript.substring(0, 5000),
  recordingUrl,
  summary: summary.substring(0, 1000),
  successEval,
  resultado,
  citaAgendada,
  nombreContacto,
  objecion,
  interes,
  callbackDatetime,
  email,
  fecha
} }];

const d = $json;
const nombre = d.nombreContacto || '';
const bookingUrl = 'https://app.cal.eu/ventas-pb/discovery-call';
const contactInfo = 'Mas info: admin@psycoboost.com | WA: wa.me/34982685874';

// Determine resultado category
let resultado = (d.resultado || '').toLowerCase().trim();

// If no resultado from structured data, infer from call data
if (!resultado) {
  if (d.citaAgendada) {
    resultado = 'cita_agendada';
  } else if (d.endedReason === 'customer-did-not-answer') {
    resultado = 'no_contesta';
  } else if (d.endedReason === 'voicemail-reached' || d.transcript.toLowerCase().includes('buzon')) {
    resultado = 'buzon_voz';
  } else if (d.duration < 15) {
    resultado = 'no_contesta';
  } else {
    resultado = 'no_interesado';
  }
}

// Normalize resultado to known categories
const resultadoMap = {
  'cita_agendada': 'cita_agendada',
  'cita_manual': 'cita_manual',
  'llamar_despues': 'llamar_despues',
  'interesado_no_agendo': 'interesado_no_agendo',
  'interesado': 'interesado_no_agendo',
  'pedir_info': 'pedir_info',
  'no_interesado': 'no_interesado',
  'gatekeeper': 'gatekeeper',
  'no_contesta': 'no_contesta',
  'buzon_voz': 'buzon_voz',
  'error_booking': 'error_booking'
};
const normalizedResultado = resultadoMap[resultado] || resultado;

// Map nivel_interes
let nivelInteres = 'bajo';
if (['cita_agendada', 'cita_manual'].includes(normalizedResultado)) {
  nivelInteres = 'alto';
} else if (['llamar_despues', 'interesado_no_agendo', 'pedir_info', 'error_booking'].includes(normalizedResultado)) {
  nivelInteres = 'medio';
}

// Build SMS text based on resultado
let smsText = '';
let shouldSendSMS = false;
const nombreSaludo = nombre ? nombre : '';

switch (normalizedResultado) {
  case 'cita_agendada':
  case 'cita_manual':
    smsText = 'Tu sesion esta confirmada! Te enviamos detalles pronto. ' + contactInfo;
    shouldSendSMS = true;
    break;
  case 'llamar_despues':
    const cuando = d.callbackDatetime ? d.callbackDatetime : 'pronto';
    smsText = (nombreSaludo ? 'Hola ' + nombreSaludo + ', ' : 'Hola, ') + 'como hemos quedado te llamo ' + cuando + '. Si necesitas algo: ' + contactInfo;
    shouldSendSMS = true;
    break;
  case 'interesado_no_agendo':
  case 'pedir_info':
    smsText = (nombreSaludo ? 'Hola ' + nombreSaludo + ', ' : 'Hola, ') + 'ha sido un placer hablar contigo. Te dejo el enlace por si quieres agendar tu sesion: ' + bookingUrl + '. ' + contactInfo;
    shouldSendSMS = true;
    break;
  case 'error_booking':
    smsText = (nombreSaludo ? 'Hola ' + nombreSaludo + ', ' : 'Hola, ') + 'disculpa, hemos tenido un problema tecnico. Puedes agendar directamente aqui: ' + bookingUrl + '. O escribenos: ' + contactInfo;
    shouldSendSMS = true;
    break;
  case 'no_interesado':
  case 'gatekeeper':
  case 'no_contesta':
  case 'buzon_voz':
    shouldSendSMS = false;
    break;
  default:
    shouldSendSMS = false;
}

// Determine estado_seguimiento
let estadoSeguimiento = 'completado';
if (['llamar_despues'].includes(normalizedResultado)) {
  estadoSeguimiento = 'pendiente_callback';
} else if (['interesado_no_agendo', 'pedir_info'].includes(normalizedResultado)) {
  estadoSeguimiento = 'pendiente_seguimiento';
} else if (['no_contesta', 'buzon_voz', 'gatekeeper'].includes(normalizedResultado)) {
  estadoSeguimiento = 'sin_contacto';
} else if (['cita_agendada', 'cita_manual'].includes(normalizedResultado)) {
  estadoSeguimiento = 'cita_programada';
}

return [{ json: {
  ...d,
  resultado: normalizedResultado,
  nivelInteres,
  estadoSeguimiento,
  smsText,
  shouldSendSMS,
  isMobile: d.phone9.startsWith('6') || d.phone9.startsWith('7')
} }];
